const mainStdoutGuard = installBrokenPipeGuard(process.stdout)
const mainStderrGuard =
  process.stderr === process.stdout
    ? mainStdoutGuard
    : installBrokenPipeGuard(process.stderr)

function isBrokenPipeWriteError(error) {
  return Boolean(
    error &&
      typeof error === 'object' &&
      error.code === 'EPIPE' &&
      error.syscall === 'write',
  )
}

function installBrokenPipeGuard(stream) {
  const guard = { broken: false }

  if (!stream || typeof stream.on !== 'function') {
    guard.broken = true
    return guard
  }

  stream.on('error', (error) => {
    if (isBrokenPipeWriteError(error)) {
      guard.broken = true
      return
    }

    setImmediate(() => {
      throw error
    })
  })

  return guard
}

function canWriteToGuardedStream(stream, guard) {
  return Boolean(
    stream &&
      guard &&
      guard.broken !== true &&
      stream.destroyed !== true &&
      stream.writableEnded !== true,
  )
}

function writeToGuardedStream(stream, guard, text) {
  if (!canWriteToGuardedStream(stream, guard)) {
    return false
  }

  try {
    stream.write(text)
    return true
  } catch (error) {
    if (isBrokenPipeWriteError(error)) {
      guard.broken = true
      return false
    }

    throw error
  }
}

function formatMainDebugDetails(details) {
  return formatMainDebugDetailsHelper(details)
}

function debugMainLog(label, details) {
  const message =
    details === undefined
      ? `[main-debug] ${label}\n`
      : `[main-debug] ${label} ${formatMainDebugDetails(details)}\n`

  if (writeToGuardedStream(process.stdout, mainStdoutGuard, message)) {
    return
  }

  writeToGuardedStream(process.stderr, mainStderrGuard, message)
}

function compactGeneratedDomainContractDebugAbsolutePath(value) {
  const normalized =
    typeof value === 'string' ? value.trim().replace(/\\/gu, '/') : ''
  if (!normalized || normalized.length <= 48) {
    return normalized
  }

  const segments = normalized.split('/').filter(Boolean)
  if (segments.length <= 3) {
    return normalized
  }

  if (/^[A-Za-z]:\//u.test(normalized)) {
    return `${normalized.slice(0, 2)}/.../${segments.slice(-3).join('/')}`
  }

  if (normalized.startsWith('/')) {
    return `/.../${segments.slice(-3).join('/')}`
  }

  return `.../${segments.slice(-3).join('/')}`
}

function compactGeneratedDomainContractDebugAbsolutePaths(value) {
  const normalized = typeof value === 'string' ? value : ''
  if (!normalized) {
    return ''
  }

  const withWindowsPathsCompacted = normalized.replace(
    /[A-Za-z]:[\\/](?:[^\\/\s"'`]+[\\/])*[^\\/\s"'`]+/gu,
    (entry) => compactGeneratedDomainContractDebugAbsolutePath(entry),
  )

  return withWindowsPathsCompacted.replace(
    /(^|[\s("'`])\/(?:[^\/\s"'`]+\/){2,}[^\/\s"'`]+/gu,
    (entry, prefix) =>
      `${prefix}${compactGeneratedDomainContractDebugAbsolutePath(entry.slice(prefix.length))}`,
  )
}

function sanitizeGeneratedDomainContractDebugPreview(value, maxLength = 240) {
  const normalized =
    typeof value === 'string'
      ? value
      : value === null || value === undefined
        ? ''
        : String(value)
  if (!normalized.trim()) {
    return ''
  }

  let sanitized = normalized.replace(/\s+/gu, ' ').trim()

  sanitized = sanitized.replace(
    /\bheaders?\b\s*[:=]\s*(?:\{[^{}]*\}|\[[^[\]]*\]|"[^"]*"|'[^']*'|[^\s,;]+)/giu,
    'headers:[redacted]',
  )
  sanitized = sanitized.replace(
    /\bbod(?:y|ies)\b\s*[:=]\s*(?:\{[^{}]*\}|\[[^[\]]*\]|"[^"]*"|'[^']*'|[^\s,;]+)/giu,
    'body:[redacted]',
  )
  sanitized = sanitized.replace(
    /\bpayload\b\s*[:=]\s*(?:\{[^{}]*\}|\[[^[\]]*\]|"[^"]*"|'[^']*'|[^\s,;]+)/giu,
    'payload:[redacted]',
  )
  sanitized = sanitized.replace(
    /\b((?:api[_-]?key|access[_-]?token|refresh[_-]?token|id[_-]?token|token|secret|password|authorization))\b(\s*[:=]\s*)(?:"[^"]*"|'[^']*'|[^\s,;]+)/giu,
    (_match, key, separator) => `${key}${separator}[redacted]`,
  )
  sanitized = sanitized.replace(/\bBearer\s+[A-Za-z0-9._~+/=-]+\b/giu, 'Bearer [redacted]')
  sanitized = sanitized.replace(/\bsk-[A-Za-z0-9_-]{8,}\b/gu, '[redacted-api-key]')
  sanitized = compactGeneratedDomainContractDebugAbsolutePaths(sanitized)

  return buildOutputPreview(sanitized, maxLength)
}

function summarizeGeneratedDomainContractDebugEntries(entries, maxEntries = 3) {
  if (!Array.isArray(entries) || maxEntries <= 0) {
    return {
      firstEntry: undefined,
      preview: [],
    }
  }

  const preview = []
  const seen = new Set()

  for (const entry of entries) {
    const sanitized = sanitizeGeneratedDomainContractDebugPreview(entry, 240)
    if (!sanitized || seen.has(sanitized)) {
      continue
    }

    seen.add(sanitized)
    preview.push(sanitized)

    if (preview.length >= maxEntries) {
      break
    }
  }

  return {
    firstEntry: preview[0],
    preview,
  }
}

function summarizeGeneratedDomainContractDiagnosticsForDebug(diagnostics) {
  if (!diagnostics || typeof diagnostics !== 'object') {
    return {
      present: false,
    }
  }

  const errorSummary = summarizeGeneratedDomainContractDebugEntries(diagnostics.errors)
  const warningSummary = summarizeGeneratedDomainContractDebugEntries(diagnostics.warnings)

  return {
    present: diagnostics.present === true,
    valid: diagnostics.valid === true,
    safeForLocalMaterialization: diagnostics.safeForLocalMaterialization === true,
    domainSlug:
      typeof diagnostics.domainSlug === 'string' && diagnostics.domainSlug.trim()
        ? diagnostics.domainSlug.trim()
        : undefined,
    rootSlug:
      typeof diagnostics.rootSlug === 'string' && diagnostics.rootSlug.trim()
        ? diagnostics.rootSlug.trim()
        : undefined,
    sourceRoot:
      typeof diagnostics.sourceRoot === 'string' && diagnostics.sourceRoot.trim()
        ? diagnostics.sourceRoot.trim()
        : undefined,
    targetRoot:
      typeof diagnostics.targetRoot === 'string' && diagnostics.targetRoot.trim()
        ? diagnostics.targetRoot.trim()
        : undefined,
    errorsCount: Array.isArray(diagnostics.errors) ? diagnostics.errors.length : 0,
    warningsCount: Array.isArray(diagnostics.warnings) ? diagnostics.warnings.length : 0,
    ...(errorSummary.firstEntry ? { firstError: errorSummary.firstEntry } : {}),
    ...(errorSummary.preview.length > 0 ? { errorsPreview: errorSummary.preview } : {}),
    ...(warningSummary.firstEntry ? { firstWarning: warningSummary.firstEntry } : {}),
    ...(warningSummary.preview.length > 0 ? { warningsPreview: warningSummary.preview } : {}),
    allowedTargetPathsCount: Number.isInteger(diagnostics.allowedTargetPathsCount)
      ? diagnostics.allowedTargetPathsCount
      : 0,
    requiredPathGroupsCount: Number.isInteger(diagnostics.requiredPathGroupsCount)
      ? diagnostics.requiredPathGroupsCount
      : 0,
  }
}

function summarizeGeneratedDomainContractObservationForDebug(observation) {
  if (!observation || typeof observation !== 'object') {
    return {
      attempted: false,
      ok: false,
      status: 'skipped',
    }
  }

  const diagnostics =
    observation.generatedDomainContractDiagnostics &&
    typeof observation.generatedDomainContractDiagnostics === 'object'
      ? observation.generatedDomainContractDiagnostics
      : null

  const errorSummary = summarizeGeneratedDomainContractDebugEntries(diagnostics?.errors)
  const warningSummary = summarizeGeneratedDomainContractDebugEntries(diagnostics?.warnings)

  return {
    requestId:
      typeof observation.requestId === 'string' && observation.requestId.trim()
        ? observation.requestId.trim()
        : undefined,
    attempted: observation.attempted === true,
    ok: observation.ok === true,
    status:
      typeof observation.status === 'string' && observation.status.trim()
        ? observation.status.trim()
        : 'skipped',
    elapsedMs:
      Number.isFinite(observation.elapsedMs) && observation.elapsedMs >= 0
        ? observation.elapsedMs
        : 0,
    errorKind:
      typeof observation.errorKind === 'string' && observation.errorKind.trim()
        ? observation.errorKind.trim()
        : undefined,
    errorPreview:
      typeof observation.errorPreview === 'string' && observation.errorPreview.trim()
        ? buildSafeGeneratedDomainContractObservationErrorPreview(observation.errorPreview)
        : undefined,
    present: diagnostics?.present === true,
    valid: diagnostics?.valid === true,
    safeForLocalMaterialization: diagnostics?.safeForLocalMaterialization === true,
    domainSlug:
      typeof diagnostics?.domainSlug === 'string' && diagnostics.domainSlug.trim()
        ? diagnostics.domainSlug.trim()
        : undefined,
    rootSlug:
      typeof diagnostics?.rootSlug === 'string' && diagnostics.rootSlug.trim()
        ? diagnostics.rootSlug.trim()
        : undefined,
    sourceRoot:
      typeof diagnostics?.sourceRoot === 'string' && diagnostics.sourceRoot.trim()
        ? diagnostics.sourceRoot.trim()
        : undefined,
    targetRoot:
      typeof diagnostics?.targetRoot === 'string' && diagnostics.targetRoot.trim()
        ? diagnostics.targetRoot.trim()
        : undefined,
    errorsCount: Array.isArray(diagnostics?.errors) ? diagnostics.errors.length : 0,
    warningsCount: Array.isArray(diagnostics?.warnings)
      ? diagnostics.warnings.length
      : 0,
    ...(errorSummary.firstEntry ? { firstError: errorSummary.firstEntry } : {}),
    ...(errorSummary.preview.length > 0 ? { errorsPreview: errorSummary.preview } : {}),
    ...(warningSummary.firstEntry ? { firstWarning: warningSummary.firstEntry } : {}),
    ...(warningSummary.preview.length > 0 ? { warningsPreview: warningSummary.preview } : {}),
  }
}

function summarizeGeneratedDomainContractComparisonForDebug(comparison) {
  if (!comparison || typeof comparison !== 'object') {
    return {
      present: false,
      compared: false,
      status: 'not-available',
    }
  }

  const warnings = Array.isArray(comparison.warnings) ? comparison.warnings : []
  const errors = Array.isArray(comparison.errors) ? comparison.errors : []

  return {
    present: comparison.present === true,
    compared: comparison.compared === true,
    status:
      typeof comparison.status === 'string' && comparison.status.trim()
        ? comparison.status.trim()
        : 'not-available',
    safeForDiagnostics: comparison.safeForDiagnostics === true,
    domainAligned: comparison.domain?.aligned === true,
    rootsAligned: comparison.roots?.aligned === true,
    backendAligned: comparison.backend?.aligned === true,
    databaseAligned: comparison.database?.aligned === true,
    safetyAligned: comparison.safety?.aligned === true,
    materializationAligned: comparison.materialization?.aligned === true,
    warningsCount: warnings.length,
    errorsCount: errors.length,
    ...(typeof comparison.domain?.contractSlug === 'string' &&
    comparison.domain.contractSlug.trim()
      ? { contractSlug: comparison.domain.contractSlug.trim() }
      : {}),
    ...(typeof comparison.roots?.contractRoot === 'string' &&
    comparison.roots.contractRoot.trim()
      ? { contractRoot: comparison.roots.contractRoot.trim() }
      : {}),
    ...(typeof comparison.roots?.legacyRoot === 'string' &&
    comparison.roots.legacyRoot.trim()
      ? { legacyRoot: comparison.roots.legacyRoot.trim() }
      : {}),
    ...(warnings.length > 0
      ? {
          firstWarning: sanitizeGeneratedDomainContractDebugPreview(warnings[0], 180),
        }
      : {}),
    ...(errors.length > 0
      ? {
          firstError: sanitizeGeneratedDomainContractDebugPreview(errors[0], 180),
        }
      : {}),
  }
}

function summarizeGeneratedDomainCapabilityProfileForDebug(profile) {
  if (!profile || typeof profile !== 'object') {
    return {
      present: false,
      built: false,
      status: 'not-available',
    }
  }

  const warnings = Array.isArray(profile.warnings) ? profile.warnings : []
  const errors = Array.isArray(profile.errors) ? profile.errors : []
  const activeWorkflows = Object.entries(
    profile.workflows && typeof profile.workflows === 'object' ? profile.workflows : {},
  )
    .filter(([, enabled]) => enabled === true)
    .map(([key]) => key)
    .slice(0, 8)

  return {
    present: profile.present === true,
    built: profile.built === true,
    status:
      typeof profile.status === 'string' && profile.status.trim()
        ? profile.status.trim()
        : 'not-available',
    deliveryLevel:
      typeof profile.delivery?.level === 'string' && profile.delivery.level.trim()
        ? profile.delivery.level.trim()
        : undefined,
    fullstackLocal: profile.delivery?.fullstackLocal === true,
    surfacesCount: Number.isInteger(profile.surfaces?.count) ? profile.surfaces.count : 0,
    backendPresent: profile.backend?.present === true,
    databasePresent: profile.database?.present === true,
    activeWorkflows,
    safeForLocalMaterialization: profile.safety?.safeForLocalMaterialization === true,
    allowedTargetPathsCount: Number.isInteger(profile.materialization?.allowedTargetPathsCount)
      ? profile.materialization.allowedTargetPathsCount
      : 0,
    requiredPathGroupsCount: Number.isInteger(profile.materialization?.requiredPathGroupsCount)
      ? profile.materialization.requiredPathGroupsCount
      : 0,
    warningsCount: warnings.length,
    errorsCount: errors.length,
    ...(warnings.length > 0
      ? {
          firstWarning: sanitizeGeneratedDomainContractDebugPreview(warnings[0], 180),
        }
      : {}),
    ...(errors.length > 0
      ? {
          firstError: sanitizeGeneratedDomainContractDebugPreview(errors[0], 180),
        }
      : {}),
  }
}

