  'model',
  'modelo',
  'module',
  'modules',
  'modulo',
  'modulos',
  'operacion',
  'operator',
  'operador',
  'panel',
  'public',
  'reportes',
  'review',
  'roles',
  'scripts',
  'seed',
  'shared',
