    executorMode: runtimeMetadata.executorMode,
    executorModeSource: runtimeMetadata.executorModeSource,
    bridgeMode: runtimeMetadata.bridgeMode,
    bridgeModeSource: runtimeMetadata.bridgeModeSource,
