function detectFullstackLocalDemoArchetype({
  normalizedText,
  domainUnderstanding,
  modules,
}) {
  const modulesText = summarizeUniqueExecutorStrings(modules, 20).join(' ')
  const understandingText = [
    normalizedText,
    summarizeUniqueExecutorStrings(domainUnderstanding?.primaryModules, 20).join(' '),
    summarizeUniqueExecutorStrings(domainUnderstanding?.primaryEntities, 20).join(' '),
    modulesText,
  ]
    .filter(Boolean)
    .join(' ')
  const combinedText = normalizeSectorDetectionText(understandingText)

  if (detectOnlineCoursesIntent(combinedText)) {
    return 'online-courses'
  }

  if (
    detectCommunityToolBankIntent(combinedText)
  ) {
    return 'community-tool-bank'
  }

  if (detectLogisticsTrackingIntent(combinedText)) {
    return 'logistics-tracking'
  }

  if (
    /\bveterinaria\b|\bveterinari[oa]s?\b|\bmascotas?\b|\bvacunas?\b|\bpet\b/u.test(
      combinedText,
    )
  ) {
    return 'veterinary'
  }

  if (
    /\bcanchas?\b|\breservas?\b|\bhorarios?\b|\bdisponibilidad\b|\btorneos?\b/u.test(
      combinedText,
    )
  ) {
    return 'sports-booking'
  }

  if (
    /\becommerce\b|\btienda online\b|\bcatalogo\b|\bcarrito\b|\bcheckout\b|\bproductos?\b|\borderes?\b|\bordenes?\b|\bcomercio\b|\bstock\b|\binventario\b|\bventas?\b|\bsku\b/u.test(
      combinedText,
    )
  ) {
    return 'ecommerce'
  }

  if (
    /\binmobiliari|\bpropiedades?\b|\balquiler(?:es)?\b|\bventas? inmobiliarias?\b|\btasaciones?\b|\bvisitas?\b|\bconsultas?\b|\bcorredor(?:a)?\b/u.test(
      combinedText,
    )
  ) {
    return 'real-estate'
  }

  if (
    /\bescuel|\balumnos?\b|\bfamilias?\b|\bcursos?\b|\bcomunicaciones?\b|\bboletines?\b/u.test(
      combinedText,
    )
  ) {
    return 'school-crm'
  }

  if (
    /\bdocumental\b|\bdocumentos?\b|\bexpedientes?\b|\bvencimientos?\b|\bresponsables?\b/u.test(
      combinedText,
    )
  ) {
    return 'document-management'
  }

  if (
    /\bseguridad\b|\bmonitoreo\b|\baccesos?\b|\balertas?\b|\bsensores?\b|\bzonas?\b|\bguardias?\b|\bincidentes?\b/u.test(
      combinedText,
    )
  ) {
    return 'security-monitoring'
  }

  if (
    /\bcomunidad\b|\bsocial\b|\bpublicaciones?\b|\bgrupos?\b|\bcomentarios?\b|\bmiembros?\b|\bmoderacion\b|\bfeed\b/u.test(
      combinedText,
    )
  ) {
    return 'community-social'
  }

  if (
    /\bturnos?\b|\bclinicas?\b|\bsalud\b|\bmedic[oa]s?\b|\bpacientes?\b|\bconsultorio\b/u.test(
      combinedText,
    )
  ) {
    return 'medical-clinic'
  }

  if (
    /\bsolicitudes?\b|\btickets?\b|\bhelpdesk\b|\bmesa de ayuda\b|\btramites?\b|\bgestion interna\b|\boperaciones internas?\b/u.test(
      combinedText,
    )
  ) {
    return 'operations'
  }

  return 'operations'
}

function detectCommunityToolBankIntent(normalizedText) {
  if (typeof normalizedText !== 'string' || !normalizedText.trim()) {
    return false
  }

  const hasStrongToolSignals =
    /\bherramientas?\b|\btool(?:s|bank)?\b|\binstrumental\b/u.test(normalizedText)
  const hasWeakToolSignals = /\butileria\b/u.test(normalizedText)
  const hasCommunitySignals =
    /\bcomunitari[oa]s?\b|\bbarriales?\b|\bvecin(?:o|os|a|as)\b/u.test(normalizedText)
  const hasLoanSignals =
    /\bprestamos?\b|\bsolicitar\b|\bsolicitudes?\b|\breservas?\b|\bdevoluciones?\b|\bdanad[ao]s?\b|\bestado\s+de\s+cada\s+herramienta\b/u.test(
      normalizedText,
    )
  const hasOperatorSignals =
    /\boperadores?\b|\badministrativ[oa]s?\b|\bpanel\s+operativ[oa]\b|\bpanel\s+administrativ[oa]\b/u.test(
      normalizedText,
    )

  return (
    (hasStrongToolSignals && (hasLoanSignals || hasCommunitySignals || hasOperatorSignals)) ||
    (hasWeakToolSignals && hasCommunitySignals && (hasLoanSignals || hasOperatorSignals))
  )
}

function inferFullstackLocalContractProfileFromPlanningArtifacts({
  goal = '',
  context = '',
  rootFolder = '',
  domainLabel = '',
  modules = [],
  fileHints = [],
}) {
  const normalizedModules = summarizeUniqueExecutorStrings(modules, 24)
  const normalizedFileHints = summarizeUniqueExecutorStrings(fileHints, 40)
  const inferredArchetype = detectFullstackLocalDemoArchetype({
    normalizedText: normalizeSectorDetectionText(
      [
        goal,
        context,
        rootFolder,
        domainLabel,
        normalizedModules.join(' '),
        normalizedFileHints.join(' '),
      ]
        .filter(Boolean)
        .join(' '),
    ),
    domainUnderstanding: {
      domainLabel,
      primaryModules: normalizedModules,
      primaryEntities: normalizedFileHints,
    },
    modules: [...normalizedModules, ...normalizedFileHints],
  })

  return resolveFullstackLocalContractProfile({
    goal,
    context: [context, domainLabel, rootFolder, normalizedFileHints.join(' ')].filter(Boolean).join(' '),
    domainUnderstanding: {
      domainLabel,
      primaryModules: normalizedModules,
      primaryEntities: normalizedFileHints,
    },
    modules: normalizedModules,
    archetype: inferredArchetype,
  })
}

