const CANONICAL_LOGISTICS_FULLSTACK_ROOT_ALIASES = [
  'logistics-tracking-local',
  'logistics-tracker-local',
  'logi-track-local',
]
const LEGACY_LOGISTICS_FULLSTACK_ROOT_ALIASES = ['logitrack-local-v1']
const CANONICAL_ONLINE_COURSES_FULLSTACK_ROOT_ALIASES = [
  'edu-platform-local',
  'courses-platform-local',
  'online-courses-local',
]

function buildCanonicalFullstackLocalMaterializationContract({
  rootFolder,
  fullstackContractProfile,
}) {
  const normalizedRootFolder =
    typeof rootFolder === 'string' && rootFolder.trim()
      ? rootFolder.trim()
      : 'fullstack-local'
  const profile =
    fullstackContractProfile && typeof fullstackContractProfile === 'object'
      ? fullstackContractProfile
      : {
          archetype: 'operations',
          frontendFeatureBasename: 'appointments',
          backendRouteBasename: 'appointments',
          backendModuleBasename: 'appointments',
        }
  const contractPaths = buildFullstackLocalContractPaths({
    rootFolder: normalizedRootFolder,
    fullstackContractProfile: profile,
  })
  const rootReadmePath = path.join(normalizedRootFolder, 'README.md')
  const backendPackageJsonPath = path.join(normalizedRootFolder, 'backend', 'package.json')
  const backendSrcServerPath = path.join(
    normalizedRootFolder,
    'backend',
    'src',
    'server.js',
  )
  const backendLegacyServerPath = path.join(normalizedRootFolder, 'backend', 'server.js')
  const sharedConstantsPath = path.join(normalizedRootFolder, 'shared', 'constants.js')
  const scriptsSeedPath = path.join(normalizedRootFolder, 'scripts', 'seed-local.js')
  const scriptsReadmePath = path.join(normalizedRootFolder, 'scripts', 'README.md')
  const databaseShipmentsJsonPath = path.join(
    normalizedRootFolder,
    'database',
    'shipments.json',
  )

  if (profile.archetype === 'logistics-tracking') {
    const requiredPathGroups = [
      { label: 'README.md', candidates: [rootReadmePath] },
      { label: 'docs/API.md', candidates: [contractPaths.docsApiPath] },
      {
        label: 'docs/ARCHITECTURE.md',
        candidates: [contractPaths.docsArchitecturePath],
      },
      {
        label: 'docs/DB_SCHEMA.md|docs/DATA_MODEL.md',
        candidates: [contractPaths.docsDbSchemaPath, contractPaths.docsDataModelPath],
      },
      { label: 'backend/package.json', candidates: [backendPackageJsonPath] },
      {
        label: 'backend/src/server.js|backend/server.js',
        candidates: [backendSrcServerPath, backendLegacyServerPath],
      },
      {
        label: 'backend/src/routes/shipments.js',
        candidates: [contractPaths.backendPrimaryRoutePath],
      },
      {
        label: 'backend/src/routes/tracking.js',
        candidates: [contractPaths.backendTrackingRoutePath],
      },
      { label: 'database/schema.sql', candidates: [contractPaths.databaseSchemaPath] },
      { label: 'database/seed.sql', candidates: [contractPaths.databaseSeedPath] },
      {
        label: 'frontend/admin/index.html',
        candidates: [contractPaths.frontendAdminIndexPath],
      },
      {
        label: 'frontend/admin/app.js',
        candidates: [contractPaths.frontendAdminAppPath],
      },
      {
        label: 'frontend/public/index.html',
        candidates: [contractPaths.frontendPublicIndexPath],
      },
      {
        label: 'frontend/public/app.js',
        candidates: [contractPaths.frontendPublicAppPath],
      },
      {
        label: 'shared/constants.js|shared/statuses.js',
        candidates: [sharedConstantsPath, contractPaths.sharedStatusesPath],
      },
      {
        label: 'scripts/seed-local.js|scripts/README.md',
        candidates: [scriptsSeedPath, scriptsReadmePath],
      },
    ]

    return {
      contractKind: 'logistics-fullstack-local',
      rootFolder: normalizedRootFolder,
      allowedRootBasenames: [
        ...CANONICAL_LOGISTICS_FULLSTACK_ROOT_ALIASES,
        ...LEGACY_LOGISTICS_FULLSTACK_ROOT_ALIASES,
      ],
      preferredRootBasenames: CANONICAL_LOGISTICS_FULLSTACK_ROOT_ALIASES.slice(),
      forbiddenSignals: [
        'web-scaffold-base',
        'web-sistema-de-tracking',
        'veterinaria',
        'appointments',
        'turnos',
        'pacientes',
        'mascotas',
        'reservas',
        'fullstack-local-veterinaria',
      ],
      primaryPersistencePaths: [
        contractPaths.databaseSchemaPath,
        contractPaths.databaseSeedPath,
      ],
      jsonPrimaryPersistencePaths: [databaseShipmentsJsonPath],
      requiredPathGroups,
      requiredPaths: requiredPathGroups.map((entry) => entry.label),
      expectedTargetPaths: requiredPathGroups.map((entry) => entry.candidates[0]).filter(Boolean),
    }
  }

  if (profile.archetype === 'online-courses') {
    const requiredPathGroups = [
      { label: 'README.md', candidates: [rootReadmePath] },
      { label: 'backend/package.json', candidates: [backendPackageJsonPath] },
      {
        label: 'backend/src/server.js|backend/server.js',
        candidates: [backendSrcServerPath, backendLegacyServerPath],
      },
      {
        label: 'backend/src/routes/courses.js',
        candidates: [contractPaths.backendPrimaryRoutePath],
      },
      {
        label: 'backend/src/routes/categories.js',
        candidates: [contractPaths.backendCategoriesRoutePath],
      },
      {
        label: 'backend/src/routes/modules.js',
        candidates: [contractPaths.backendModulesRoutePath],
      },
      {
        label: 'backend/src/routes/lessons.js',
        candidates: [contractPaths.backendLessonsRoutePath],
      },
      {
        label: 'backend/src/routes/students.js',
        candidates: [contractPaths.backendStudentsRoutePath],
      },
      {
        label: 'backend/src/routes/enrollments.js',
        candidates: [contractPaths.backendEnrollmentsRoutePath],
      },
      {
        label: 'backend/src/routes/plans.js',
        candidates: [contractPaths.backendPlansRoutePath],
      },
      {
        label: 'backend/src/routes/payments.js',
        candidates: [contractPaths.backendPaymentsRoutePath],
      },
      {
        label: 'backend/src/routes/progress.js',
        candidates: [contractPaths.backendProgressRoutePath],
      },
      {
        label: 'backend/src/services/mock-mercado-pago.js',
        candidates: [contractPaths.backendMockMercadoPagoServicePath],
      },
      { label: 'database/schema.sql', candidates: [contractPaths.databaseSchemaPath] },
      { label: 'database/seed.sql', candidates: [contractPaths.databaseSeedPath] },
      {
        label: 'frontend/admin/index.html',
        candidates: [contractPaths.frontendAdminIndexPath],
      },
      {
        label: 'frontend/admin/app.js',
        candidates: [contractPaths.frontendAdminAppPath],
      },
      {
        label: 'frontend/public/index.html',
        candidates: [contractPaths.frontendPublicIndexPath],
      },
      {
        label: 'frontend/public/app.js',
        candidates: [contractPaths.frontendPublicAppPath],
      },
      {
        label: 'frontend/student/index.html',
        candidates: [contractPaths.frontendStudentIndexPath],
      },
      {
        label: 'frontend/student/app.js',
        candidates: [contractPaths.frontendStudentAppPath],
      },
      { label: 'shared/plans.js', candidates: [contractPaths.sharedPlansPath] },
      {
        label: 'shared/payment-statuses.js',
        candidates: [contractPaths.sharedPaymentStatusesPath],
      },
      {
        label: 'shared/course-statuses.js',
        candidates: [contractPaths.sharedCourseStatusesPath],
      },
      { label: 'docs/API.md', candidates: [contractPaths.docsApiPath] },
      {
        label: 'docs/ARCHITECTURE.md',
        candidates: [contractPaths.docsArchitecturePath],
      },
      {
        label: 'docs/DB_SCHEMA.md|docs/DATA_MODEL.md',
        candidates: [contractPaths.docsDbSchemaPath, contractPaths.docsDataModelPath],
      },
      {
        label: 'docs/PAYMENTS_MOCK.md',
        candidates: [contractPaths.docsPaymentsMockPath],
      },
      {
        label: 'docs/LOCAL_VALIDATION.md',
        candidates: [contractPaths.docsLocalValidationPath],
      },
      {
        label: 'scripts/seed-local.js|scripts/README.md',
        candidates: [scriptsSeedPath, scriptsReadmePath],
      },
    ]

    return {
      contractKind: 'online-courses-fullstack-local',
      rootFolder: normalizedRootFolder,
      allowedRootBasenames: CANONICAL_ONLINE_COURSES_FULLSTACK_ROOT_ALIASES.slice(),
      preferredRootBasenames: CANONICAL_ONLINE_COURSES_FULLSTACK_ROOT_ALIASES.slice(),
      forbiddenSignals: [
        'web-scaffold-base',
        'shipments',
        'tracking',
        'veterinaria',
        'appointments',
        'turnos',
        'pacientes',
        'mascotas',
        'productos',
        'stock',
        'inventario',
        'fullstack-local-veterinaria',
      ],
      primaryPersistencePaths: [
        contractPaths.databaseSchemaPath,
        contractPaths.databaseSeedPath,
      ],
      jsonPrimaryPersistencePaths: [],
      requiredPathGroups,
      requiredPaths: requiredPathGroups.map((entry) => entry.label),
      expectedTargetPaths: requiredPathGroups.map((entry) => entry.candidates[0]).filter(Boolean),
    }
  }

  const genericRequiredPathGroups = [
    { label: 'README.md', candidates: [rootReadmePath] },
    { label: 'backend/package.json', candidates: [backendPackageJsonPath] },
    {
      label: 'backend/src/server.js|backend/server.js',
      candidates: [backendSrcServerPath, backendLegacyServerPath],
    },
    { label: 'database/schema.sql', candidates: [contractPaths.databaseSchemaPath] },
    {
      label: 'frontend/admin/index.html',
      candidates: [contractPaths.frontendAdminIndexPath],
    },
    {
      label: 'frontend/public/index.html',
      candidates: [contractPaths.frontendPublicIndexPath],
    },
    {
      label: 'docs/DB_SCHEMA.md|docs/DATA_MODEL.md',
      candidates: [
        contractPaths.docsDbSchemaPath,
        contractPaths.docsDataModelPath,
        path.join(normalizedRootFolder, 'docs', 'data-model.md'),
      ],
    },
  ]

  return {
    contractKind: 'generic-fullstack-local',
    rootFolder: normalizedRootFolder,
    allowedRootBasenames: [],
    preferredRootBasenames: [],
    forbiddenSignals: ['web-scaffold-base'],
    primaryPersistencePaths: [contractPaths.databaseSchemaPath],
    jsonPrimaryPersistencePaths: [databaseShipmentsJsonPath],
    requiredPathGroups: genericRequiredPathGroups,
    requiredPaths: genericRequiredPathGroups.map((entry) => entry.label),
    expectedTargetPaths: genericRequiredPathGroups
      .map((entry) => entry.candidates[0])
      .filter(Boolean),
  }
}

function collectMaterializationContractTargetPaths({ executionScope, materializationPlan }) {
  return summarizeUniqueExecutorStrings(
    [
      ...(Array.isArray(executionScope?.allowedTargetPaths)
        ? executionScope.allowedTargetPaths
        : []),
      ...(Array.isArray(materializationPlan?.allowedTargetPaths)
        ? materializationPlan.allowedTargetPaths
        : []),
      ...(Array.isArray(materializationPlan?.operations)
        ? materializationPlan.operations.flatMap((entry) => [
            entry?.targetPath || '',
            entry?.sourcePath || '',
          ])
        : []),
    ].filter((entry) => typeof entry === 'string' && entry.trim()),
    200,
  ).map((entry) => normalizePathForComparison(entry).toLocaleLowerCase())
}

function isUsableFullstackLocalInspectionDefinition(contractDefinition) {
  return (
    contractDefinition &&
    typeof contractDefinition === 'object' &&
    Array.isArray(contractDefinition.requiredPathGroups) &&
    contractDefinition.requiredPathGroups.length > 0 &&
    (Array.isArray(contractDefinition.expectedTargetPaths)
      ? contractDefinition.expectedTargetPaths.length > 0
      : contractDefinition.requiredPathGroups.some(
          (group) => Array.isArray(group?.candidates) && group.candidates.length > 0,
        ))
  )
}

function buildGeneratedDomainContractInspectionDefinition({
  generatedDomainContract,
  generatedDomainContractDiagnostics,
  generatedDomainCapabilityProfile,
}) {
  if (!generatedDomainContract || typeof generatedDomainContract !== 'object') {
    return null
  }

  try {
    const resolvedDiagnostics =
      generatedDomainContractDiagnostics &&
      typeof generatedDomainContractDiagnostics === 'object' &&
      generatedDomainContractDiagnostics.present === true
        ? generatedDomainContractDiagnostics
        : buildGeneratedDomainContractDiagnostics({ generatedDomainContract }, '.')
    const normalizedContract =
      resolvedDiagnostics?.normalizedContract &&
      typeof resolvedDiagnostics.normalizedContract === 'object'
        ? resolvedDiagnostics.normalizedContract
        : generatedDomainContract
    const capabilityProfile =
      generatedDomainCapabilityProfile &&
      typeof generatedDomainCapabilityProfile === 'object'
        ? generatedDomainCapabilityProfile
        : buildGeneratedDomainCapabilityProfile(normalizedContract, resolvedDiagnostics)
    const diagnosticsAreSafe =
      resolvedDiagnostics?.present === true &&
      resolvedDiagnostics?.valid === true &&
      resolvedDiagnostics?.safeForLocalMaterialization === true &&
      Number(resolvedDiagnostics?.errorsCount || 0) === 0
    const capabilityProfileIsSufficient =
      capabilityProfile?.present === true &&
      capabilityProfile?.built === true &&
      capabilityProfile?.delivery?.fullstackLocal === true &&
      capabilityProfile?.materialization?.hasAllowedTargets === true &&
      capabilityProfile?.materialization?.hasRequiredGroups === true

    if (!diagnosticsAreSafe || !capabilityProfileIsSufficient) {
      return null
    }

    const allowedTargetPaths =
      Array.isArray(resolvedDiagnostics?.allowedTargetPaths) &&
      resolvedDiagnostics.allowedTargetPaths.length > 0
        ? resolvedDiagnostics.allowedTargetPaths
        : deriveAllowedTargetPathsFromContract(normalizedContract, '.')
    const requiredPathGroups =
      Array.isArray(resolvedDiagnostics?.requiredPathGroups) &&
      resolvedDiagnostics.requiredPathGroups.length > 0
        ? resolvedDiagnostics.requiredPathGroups
        : deriveRequiredPathGroupsFromContract(normalizedContract)
    const forbiddenSignals = deriveForbiddenSearchPatternsFromContract(normalizedContract)
    const rootFolder =
      normalizeOptionalString(normalizedContract?.root?.targetRoot) ||
      normalizeOptionalString(normalizedContract?.root?.sourceRoot) ||
      normalizeOptionalString(normalizedContract?.root?.slug) ||
      ''
    const normalizedRequiredPathGroups = requiredPathGroups
      .map((group, index) => {
        const candidates = Array.isArray(group)
          ? group.filter((entry) => typeof entry === 'string' && entry.trim())
          : Array.isArray(group?.candidates)
            ? group.candidates.filter((entry) => typeof entry === 'string' && entry.trim())
            : []
        if (candidates.length === 0) {
          return null
        }

        return {
          label:
            normalizeOptionalString(group?.label) ||
            normalizeOptionalString(candidates[0]) ||
            `required-path-group-${index + 1}`,
          candidates,
        }
      })
      .filter(Boolean)
    const rootBasename = normalizeOptionalString(path.basename(rootFolder))
    const primaryPersistencePaths = summarizeUniqueExecutorStrings(
      [
        normalizeOptionalString(normalizedContract?.database?.schemaFile),
        normalizeOptionalString(normalizedContract?.database?.seedFile),
      ].filter(Boolean),
      16,
    )

    if (allowedTargetPaths.length === 0 || normalizedRequiredPathGroups.length === 0) {
      return null
    }

    return {
      contractKind: 'generated-domain-contract-fullstack-local',
      rootFolder: rootFolder || 'fullstack-local',
      allowedRootBasenames: rootBasename ? [rootBasename] : [],
      preferredRootBasenames: rootBasename ? [rootBasename] : [],
      forbiddenSignals: summarizeUniqueExecutorStrings(
        ['web-scaffold-base', ...forbiddenSignals],
        64,
      ),
      primaryPersistencePaths,
      jsonPrimaryPersistencePaths: [],
      requiredPathGroups: normalizedRequiredPathGroups,
      requiredPaths: normalizedRequiredPathGroups.map((entry) => entry.label),
      expectedTargetPaths: summarizeUniqueExecutorStrings(
        normalizedRequiredPathGroups.map((entry) => entry.candidates[0]).filter(Boolean),
        200,
      ),
    }
  } catch (_error) {
    return null
  }
}

function resolveFullstackLocalInspectionDefinition({
  rootFolder,
  fullstackContractProfile,
  materializationPlan,
  generatedDomainContract,
  generatedDomainContractDiagnostics,
  generatedDomainCapabilityProfile,
}) {
  const legacyContractDefinition = rootFolder
    ? buildCanonicalFullstackLocalMaterializationContract({
        rootFolder,
        fullstackContractProfile,
      })
    : null
  const explicitContractDefinition = isUsableFullstackLocalInspectionDefinition(
    materializationPlan?.contractDefinition,
  )
    ? materializationPlan.contractDefinition
    : null
  const generatedContractDefinition = buildGeneratedDomainContractInspectionDefinition({
    generatedDomainContract,
    generatedDomainContractDiagnostics,
    generatedDomainCapabilityProfile,
  })
  const warnings = []
  const errors = []
  const appendWarning = (message) => {
    const normalized =
      typeof message === 'string'
        ? message.trim()
        : message === null || message === undefined
          ? ''
          : String(message).trim()
    if (!normalized) {
      return
    }
    const bounded =
      normalized.length <= 180 ? normalized : `${normalized.slice(0, 177)}...`
    if (!warnings.includes(bounded)) {
      warnings.push(bounded)
    }
  }

  let source = 'unavailable'
  let contractDefinition = null
  let reason =
    'No hay fuente suficiente para inspeccionar el contrato fullstack local materializable.'

  if (explicitContractDefinition) {
    source = 'explicit-materialization-contract'
    contractDefinition = explicitContractDefinition
    reason =
      'La inspeccion fullstack local reutiliza materializationPlan.contractDefinition explicito.'
  } else if (generatedContractDefinition) {
    source = 'generated-domain-contract'
    contractDefinition = generatedContractDefinition
    reason =
      'La inspeccion fullstack local usa generatedDomainContract valido y suficiente antes del fallback legacy.'
  } else if (isUsableFullstackLocalInspectionDefinition(legacyContractDefinition)) {
    source = 'legacy-canonical-contract'
    contractDefinition = legacyContractDefinition
    reason =
      'La inspeccion fullstack local sigue usando el contrato canonico legacy como fallback.'
    if (generatedDomainContractDiagnostics?.present !== true) {
      appendWarning(
        'Legacy canonical inspection fallback remained active because generatedDomainContract is unavailable.',
      )
    } else {
      appendWarning(
        'Legacy canonical inspection fallback remained active because generatedDomainContract was not sufficient for inspection.',
      )
    }
  }

  return {
    contractDefinition,
    diagnostics: {
      present: true,
      source,
      behaviorChanged: false,
      generatedDomainContractUsed: source === 'generated-domain-contract',
      explicitMaterializationContractUsed:
        source === 'explicit-materialization-contract',
      legacyCanonicalContractUsed: source === 'legacy-canonical-contract',
      fallbackUsed:
        source === 'legacy-canonical-contract' || source === 'unavailable',
      reason,
      warnings,
      errors,
      warningsCount: warnings.length,
      errorsCount: errors.length,
    },
  }
}

function inspectFullstackLocalMaterializationContract({
  goal,
  context,
  decisionKey,
  strategy,
  executionMode,
  nextExpectedAction,
  executionScope,
  materializationPlan,
  localProjectManifest,
  existingProjectDetection,
  generatedDomainContract,
  generatedDomainContractDiagnostics,
  generatedDomainCapabilityProfile,
}) {
  const targetPaths = collectMaterializationContractTargetPaths({
    executionScope,
    materializationPlan,
  })
  const rootFolder =
    normalizeOptionalString(materializationPlan?.projectRoot) ||
    normalizeOptionalString(localProjectManifest?.projectRoot) ||
    (targetPaths[0] ? targetPaths[0].split('/').filter(Boolean)[0] || '' : '') ||
    ''
  const fileHints = [
    ...targetPaths,
    ...(Array.isArray(materializationPlan?.operations)
      ? materializationPlan.operations.map((entry) =>
          typeof entry?.nextContent === 'string' ? entry.nextContent.slice(0, 400) : '',
        )
      : []),
  ]
  const profile = inferFullstackLocalContractProfileFromPlanningArtifacts({
    goal,
    context,
    rootFolder,
    domainLabel: normalizeOptionalString(localProjectManifest?.domain),
    modules:
      Array.isArray(localProjectManifest?.modules) && localProjectManifest.modules.length > 0
        ? localProjectManifest.modules
        : [],
    fileHints,
  })
  const selectedDomain =
    profile.archetype === 'online-courses'
      ? 'online-courses'
      : profile.archetype === 'logistics-tracking'
        ? 'logistics-tracking'
        : profile.archetype || 'generic'
  const contractResolution = resolveFullstackLocalInspectionDefinition({
    rootFolder,
    fullstackContractProfile: profile,
    materializationPlan,
    generatedDomainContract,
    generatedDomainContractDiagnostics,
    generatedDomainCapabilityProfile,
  })
  const contractDefinition = contractResolution.contractDefinition
  const fullstackLocalInspectionSourceDiagnostics = contractResolution.diagnostics
  if (!isUsableFullstackLocalInspectionDefinition(contractDefinition)) {
    return {
      ok: false,
      reason: fullstackLocalInspectionSourceDiagnostics.reason,
      missingRequiredPaths: [],
      forbiddenSignalsFound: [],
      usesJsonAsPrimaryPersistence: false,
      rootPath: rootFolder,
      contractKind: '',
      expectedTargetPaths: [],
      allowedRootBasenames: [],
      preferredRootBasenames: [],
      usesLogisticsContract: false,
      selectedDomain,
      hasSqlContract: false,
      hasCanonicalDataModelDoc: false,
      missingRequiredMarkers: [],
      contaminationTokens: [],
      valid: false,
      fullstackLocalInspectionSourceDiagnostics,
      legacyDomainResolution: {
        fullstackLocalArchetype: profile.archetype || '',
        usedLegacyArchetype:
          typeof profile.archetype === 'string' &&
          profile.archetype.trim() &&
          profile.archetype.trim() !== 'operations',
        canonicalMaterializationContractKind: '',
        usedCanonicalMaterializationContract: false,
        selectedDomain,
        materializationPlanProfileKey: profile.archetype || '',
        usedLegacyMaterializationProfile:
          typeof profile.archetype === 'string' &&
          profile.archetype.trim() &&
          profile.archetype.trim() !== 'operations',
      },
    }
  }
  const usesCanonicalSpecializedContract =
    contractDefinition.contractKind === 'logistics-fullstack-local' ||
    contractDefinition.contractKind === 'online-courses-fullstack-local'
  const normalizedTargetSummary = targetPaths.join(' ')
  const resolvedExpectedTargetPaths = contractDefinition.requiredPathGroups
    .map((group) =>
      group.candidates.find((entry) =>
        normalizedTargetSummary.includes(
          normalizePathForComparison(entry).toLocaleLowerCase(),
        ),
      ) || group.candidates[0],
    )
    .filter(Boolean)
  const missingRequiredPaths = contractDefinition.requiredPathGroups
    .filter(
      (group) =>
        !group.candidates.some((entry) =>
          normalizedTargetSummary.includes(
            normalizePathForComparison(entry).toLocaleLowerCase(),
          ),
        ),
    )
    .map((group) => group.label)
  const hasCanonicalDataModelDoc = contractDefinition.requiredPathGroups
    .find((entry) => /docs\/db_schema\.md|docs\/data_model\.md/iu.test(String(entry.label || '')))
    ?.candidates.some((entry) =>
      normalizedTargetSummary.includes(
        normalizePathForComparison(entry).toLocaleLowerCase(),
      ),
    )
  const normalizedPrimaryPersistencePaths = summarizeUniqueExecutorStrings(
    contractDefinition.primaryPersistencePaths,
    16,
  )
    .map((entry) => normalizePathForComparison(entry).toLocaleLowerCase())
    .filter(Boolean)
  const hasSqlContract =
    normalizedPrimaryPersistencePaths.length > 0 &&
    normalizedPrimaryPersistencePaths.every((entry) => normalizedTargetSummary.includes(entry))
  const usesJsonAsPrimaryPersistence =
    summarizeUniqueExecutorStrings(contractDefinition.jsonPrimaryPersistencePaths, 16).some((entry) =>
      targetPaths.some((targetPath) =>
        targetPath.endsWith(normalizePathForComparison(entry).toLocaleLowerCase()),
      ),
    ) && !hasSqlContract
  const normalizedRootBasename = normalizePathForComparison(
    path.basename(rootFolder || contractDefinition.rootFolder || ''),
  ).toLocaleLowerCase()
  const rootAliasMismatch =
    (usesCanonicalSpecializedContract ||
      fullstackLocalInspectionSourceDiagnostics.source === 'generated-domain-contract') &&
    Array.isArray(contractDefinition.allowedRootBasenames) &&
    contractDefinition.allowedRootBasenames.length > 0 &&
    !contractDefinition.allowedRootBasenames.some(
      (entry) => normalizePathForComparison(entry).toLocaleLowerCase() === normalizedRootBasename,
    )
  const normalizedDecisionSummary = normalizeSectorDetectionText(
    [
      goal,
      context,
      normalizeOptionalString(decisionKey),
      normalizeOptionalString(strategy),
      normalizeOptionalString(executionMode),
      normalizeOptionalString(nextExpectedAction),
      normalizeOptionalString(materializationPlan?.projectRoot),
      normalizeOptionalString(localProjectManifest?.projectRoot),
      normalizeOptionalString(existingProjectDetection?.projectRoot),
      ...targetPaths,
    ]
      .filter(Boolean)
      .join(' '),
  )
  const normalizedDetectedProjectRoot = normalizePathForComparison(
    normalizeOptionalString(existingProjectDetection?.projectRoot),
  ).toLocaleLowerCase()
  const shouldIgnoreDetectedProjectSignals =
    existingProjectDetection?.applicable === false ||
    (normalizedDetectedProjectRoot &&
      !targetPaths.some((entry) => entry.includes(normalizedDetectedProjectRoot)))
  const contaminationText = normalizeSectorDetectionText(
    [
      normalizeOptionalString(decisionKey),
      normalizeOptionalString(strategy),
      normalizeOptionalString(executionMode),
      normalizeOptionalString(nextExpectedAction),
      normalizeOptionalString(localProjectManifest?.domain),
      ...(shouldIgnoreDetectedProjectSignals
        ? []
        : [
            normalizeOptionalString(existingProjectDetection?.projectRoot),
            normalizeOptionalString(existingProjectDetection?.domain),
          ]),
      ...(Array.isArray(localProjectManifest?.modules) ? localProjectManifest.modules : []),
      ...targetPaths,
      ...(Array.isArray(materializationPlan?.operations)
        ? materializationPlan.operations.flatMap((entry) => [
            normalizeOptionalString(entry?.targetPath),
            typeof entry?.nextContent === 'string' ? entry.nextContent.slice(0, 1000) : '',
          ])
        : []),
    ]
      .filter(Boolean)
      .join(' '),
  )
  const forbiddenSignalsFound = [
    ...(usesCanonicalSpecializedContract &&
    String(strategy || '').trim() !== 'materialize-fullstack-local-plan'
      ? ['strategy-not-materialize-fullstack-local-plan']
      : []),
    ...(usesCanonicalSpecializedContract && String(executionMode || '').trim() !== 'executor'
      ? ['executionMode-not-executor']
      : []),
    ...(usesCanonicalSpecializedContract && String(nextExpectedAction || '').trim() !== 'execute-plan'
      ? ['nextExpectedAction-not-execute-plan']
      : []),
    ...(rootAliasMismatch ? ['unexpected-root-path'] : []),
    ...contractDefinition.forbiddenSignals.filter((token) =>
      contaminationText.includes(normalizeSectorDetectionText(token)),
    ),
    ...(normalizedDecisionSummary.includes(normalizeSectorDetectionText('index.html')) &&
    normalizedDecisionSummary.includes(normalizeSectorDetectionText('styles.css')) &&
    normalizedDecisionSummary.includes(normalizeSectorDetectionText('script.js')) &&
    !normalizedDecisionSummary.includes(normalizeSectorDetectionText('backend/src/server.js')) &&
    !normalizedDecisionSummary.includes(normalizeSectorDetectionText('database/schema.sql'))
      ? ['landing-only-surface']
      : []),
  ]
  let reason = 'Contrato fullstack local válido.'

  if (String(strategy || '').trim() !== 'materialize-fullstack-local-plan') {
    reason =
      'El contrato fullstack local debe usar strategy materialize-fullstack-local-plan.'
  } else if (String(executionMode || '').trim() !== 'executor') {
    reason = 'El contrato fullstack local debe usar executionMode executor.'
  } else if (String(nextExpectedAction || '').trim() !== 'execute-plan') {
    reason = 'El contrato fullstack local debe usar nextExpectedAction execute-plan.'
  } else if (usesJsonAsPrimaryPersistence || !hasSqlContract) {
    reason = 'Falta contrato SQL local: database/schema.sql y database/seed.sql.'
  } else if (missingRequiredPaths.length > 0) {
    reason = `Faltan rutas obligatorias del contrato: ${missingRequiredPaths.join(', ')}.`
  } else if (forbiddenSignalsFound.length > 0) {
    reason = `Se detectaron señales incompatibles con el contrato fullstack: ${forbiddenSignalsFound.join(', ')}.`
  }
  const ok =
    String(strategy || '').trim() === 'materialize-fullstack-local-plan' &&
    String(executionMode || '').trim() === 'executor' &&
    String(nextExpectedAction || '').trim() === 'execute-plan' &&
    missingRequiredPaths.length === 0 &&
    hasSqlContract &&
    (!usesCanonicalSpecializedContract || hasCanonicalDataModelDoc !== false) &&
    forbiddenSignalsFound.length === 0 &&
    !usesJsonAsPrimaryPersistence

  return {
    ok,
    reason,
    missingRequiredPaths,
    forbiddenSignalsFound,
    usesJsonAsPrimaryPersistence,
    rootPath: rootFolder,
    contractKind: contractDefinition.contractKind,
    expectedTargetPaths: resolvedExpectedTargetPaths,
    allowedRootBasenames: contractDefinition.allowedRootBasenames,
    preferredRootBasenames: contractDefinition.preferredRootBasenames,
    usesLogisticsContract: profile.archetype === 'logistics-tracking',
    selectedDomain,
    hasSqlContract,
    hasCanonicalDataModelDoc,
    missingRequiredMarkers: missingRequiredPaths,
    contaminationTokens: forbiddenSignalsFound,
    valid: ok,
    fullstackLocalInspectionSourceDiagnostics,
    legacyDomainResolution: {
      fullstackLocalArchetype: profile.archetype || '',
      usedLegacyArchetype:
        typeof profile.archetype === 'string' &&
        profile.archetype.trim() &&
        profile.archetype.trim() !== 'operations',
      canonicalMaterializationContractKind: contractDefinition.contractKind || '',
      usedCanonicalMaterializationContract:
        typeof contractDefinition.contractKind === 'string' &&
        contractDefinition.contractKind.trim() &&
        contractDefinition.contractKind.trim() !== 'generic-fullstack-local',
      selectedDomain,
      materializationPlanProfileKey: profile.archetype || '',
      usedLegacyMaterializationProfile:
        typeof profile.archetype === 'string' &&
        profile.archetype.trim() &&
        profile.archetype.trim() !== 'operations',
    },
  }
}

function resolveFullstackLocalContractProfile({
  goal,
  context,
  domainUnderstanding,
  modules,
  archetype,
}) {
  const resolvedArchetype =
    typeof archetype === 'string' && archetype.trim()
      ? archetype.trim()
      : detectFullstackLocalDemoArchetype({
          normalizedText: normalizeSectorDetectionText(
            [
              goal,
              context,
              summarizeUniqueExecutorStrings(domainUnderstanding?.primaryModules, 20).join(' '),
              summarizeUniqueExecutorStrings(domainUnderstanding?.primaryEntities, 20).join(' '),
              summarizeUniqueExecutorStrings(modules, 20).join(' '),
            ]
              .filter(Boolean)
              .join(' '),
          ),
          domainUnderstanding,
          modules,
        })

  if (resolvedArchetype === 'logistics-tracking') {
    return {
      archetype: resolvedArchetype,
      frontendFeatureBasename: 'shipments',
      backendModuleBasename: 'shipments',
      backendRouteBasename: 'shipments',
      primaryFeatureLabel: 'envios y tracking',
      primaryRoutePath: '/shipments',
      primaryRoutePurpose: 'Listar envios mock y su trazabilidad local.',
      publicRoutePath: '/tracking/:code',
      publicRoutePurpose: 'Consultar tracking publico mock por codigo sin servicios reales.',
      validationSchemaMarker: 'create table shipments',
    }
  }

  if (resolvedArchetype === 'online-courses') {
    return {
      archetype: resolvedArchetype,
      frontendFeatureBasename: 'courses',
      backendModuleBasename: 'courses',
      backendRouteBasename: 'courses',
      primaryFeatureLabel: 'cursos, acceso y progreso',
      primaryRoutePath: '/courses',
      primaryRoutePurpose: 'Listar cursos mock y su acceso por plan en modo local.',
      publicRoutePath: '/catalog',
      publicRoutePurpose: 'Explorar el catálogo público local de cursos sin servicios externos.',
      validationSchemaMarker: 'create table courses',
    }
  }

  if (resolvedArchetype === 'community-tool-bank') {
    return {
      archetype: resolvedArchetype,
      frontendFeatureBasename: 'tools',
      backendModuleBasename: 'tools',
      backendRouteBasename: 'tools',
      primaryFeatureLabel: 'herramientas, prestamos y reservas',
      primaryRoutePath: '/tools',
      primaryRoutePurpose:
        'Listar herramientas, disponibilidad, prestamos y reservas mock en modo local.',
      publicRoutePath: '/catalog',
      publicRoutePurpose:
        'Consultar el catalogo local de herramientas disponibles sin servicios reales.',
      validationSchemaMarker: 'create table tools',
    }
  }

  return {
    archetype: resolvedArchetype,
    frontendFeatureBasename: 'appointments',
    backendModuleBasename: 'appointments',
    backendRouteBasename: 'appointments',
    primaryFeatureLabel: 'flujo principal del dominio',
    primaryRoutePath: '/appointments',
    primaryRoutePurpose: 'Listar registros mock del flujo principal local.',
    publicRoutePath: '',
    publicRoutePurpose: '',
    validationSchemaMarker: '',
  }
}

