function buildFullstackLocalDemoData({
  appTitle,
  normalizedText,
  domainUnderstanding,
  modules,
  nextRecommendedPhase,
}) {
  const archetype = detectFullstackLocalDemoArchetype({
    normalizedText,
    domainUnderstanding,
    modules,
  })

  switch (archetype) {
    case 'veterinary':
      return buildVeterinaryFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'medical-clinic':
      return buildMedicalFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'sports-booking':
      return buildSportsBookingFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'ecommerce':
      return buildEcommerceFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'online-courses':
      return buildOnlineCoursesFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'community-tool-bank':
      return buildCommunityToolBankFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'real-estate':
      return buildRealEstateFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'school-crm':
      return buildSchoolCrmFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'document-management':
      return buildDocumentManagementFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'security-monitoring':
      return buildSecurityMonitoringFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'logistics-tracking':
      return buildLogisticsTrackingFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    case 'community-social':
      return buildCommunitySocialFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
    default:
      return buildOperationsFullstackLocalDemoData({
        appTitle,
        nextRecommendedPhase,
      })
  }
}

