  const schemaContent = `-- Database design local y revisable para turnos medicos.
-- No ejecutar este archivo automaticamente.

CREATE TABLE patients (
  id TEXT PRIMARY KEY,
  full_name TEXT NOT NULL,
  document_number TEXT NOT NULL,
  contact_phone TEXT,
  contact_email TEXT,
  notes TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL
);

CREATE TABLE professionals (
  id TEXT PRIMARY KEY,
  full_name TEXT NOT NULL,
  license_code TEXT,
  contact_phone TEXT,
  contact_email TEXT,
  status TEXT NOT NULL,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL
);

CREATE TABLE specialties (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  description TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL
);

CREATE TABLE professional_specialties (
  professional_id TEXT NOT NULL,
  specialty_id TEXT NOT NULL,
  primary_flag INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL,
  PRIMARY KEY (professional_id, specialty_id),
  FOREIGN KEY (professional_id) REFERENCES professionals(id),
  FOREIGN KEY (specialty_id) REFERENCES specialties(id)
);

CREATE TABLE availability_slots (
  id TEXT PRIMARY KEY,
  professional_id TEXT NOT NULL,
  specialty_id TEXT NOT NULL,
  slot_date TEXT NOT NULL,
  start_time TEXT NOT NULL,
  end_time TEXT NOT NULL,
  state TEXT NOT NULL,
  notes TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL,
  FOREIGN KEY (professional_id) REFERENCES professionals(id),
  FOREIGN KEY (specialty_id) REFERENCES specialties(id)
);

CREATE TABLE appointments (
  id TEXT PRIMARY KEY,
  patient_id TEXT NOT NULL,
  professional_id TEXT NOT NULL,
  specialty_id TEXT NOT NULL,
  availability_slot_id TEXT NOT NULL,
  appointment_date TEXT NOT NULL,
  status TEXT NOT NULL,
  reason TEXT,
  notes TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL,
  FOREIGN KEY (patient_id) REFERENCES patients(id),
  FOREIGN KEY (professional_id) REFERENCES professionals(id),
  FOREIGN KEY (specialty_id) REFERENCES specialties(id),
  FOREIGN KEY (availability_slot_id) REFERENCES availability_slots(id)
);

CREATE TABLE appointment_status_history (
  id TEXT PRIMARY KEY,
  appointment_id TEXT NOT NULL,
  previous_status TEXT,
  next_status TEXT NOT NULL,
  changed_at TEXT NOT NULL,
  changed_by TEXT NOT NULL,
  change_reason TEXT,
  FOREIGN KEY (appointment_id) REFERENCES appointments(id)
);

CREATE TABLE notifications (
  id TEXT PRIMARY KEY,
  appointment_id TEXT NOT NULL,
  patient_id TEXT NOT NULL,
  notification_type TEXT NOT NULL,
  notification_status TEXT NOT NULL,
  channel TEXT NOT NULL,
  detail TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL,
  FOREIGN KEY (appointment_id) REFERENCES appointments(id),
  FOREIGN KEY (patient_id) REFERENCES patients(id)
);
`
